# This is an example of how to generate bindings for an Android module. We should
# eventually build a more comprehensive script (perhaps in Python) for regenerating
# the bindings of all modules (+ any patches we want to apply to modules
# post-generation)
swift run swift-java wrap-java --output-directory Sources/AndroidAppWidget --swift-module AndroidAppWidget --depends-on AndroidAnimation=Sources/AndroidAnimation/swift-java.config --depends-on AndroidApp=Sources/AndroidApp/swift-java.config --depends-on AndroidAppWidget=Sources/AndroidAppWidget/swift-java.config --depends-on AndroidContent=Sources/AndroidContent/swift-java.config --depends-on AndroidGraphics=Sources/AndroidGraphics/swift-java.config --depends-on AndroidLocation=Sources/AndroidLocation/swift-java.config --depends-on AndroidMaterial=Sources/AndroidMaterial/swift-java.config --depends-on AndroidMedia=Sources/AndroidMedia/swift-java.config --depends-on AndroidNet=Sources/AndroidNet/swift-java.config --depends-on AndroidNFC=Sources/AndroidNFC/swift-java.config --depends-on AndroidOS=Sources/AndroidOS/swift-java.config --depends-on AndroidR=Sources/AndroidR/swift-java.config --depends-on AndroidUtil=Sources/AndroidUtil/swift-java.config --depends-on AndroidView=Sources/AndroidView/swift-java.config --depends-on AndroidWebKit=Sources/AndroidWebKit/swift-java.config --depends-on AndroidWidget=Sources/AndroidWidget/swift-java.config --depends-on AndroidX=Sources/AndroidX/swift-java.config
